PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE goose_db_version (
		id INTEGER PRIMARY KEY AUTOINCREMENT,
		version_id INTEGER NOT NULL,
		is_applied INTEGER NOT NULL,
		tstamp TIMESTAMP DEFAULT (datetime('now'))
	);
CREATE TABLE random_name (
    [id] integer primary key,
    [part_type] text not null,
    [name] text not null,
    unique([part_type], [name])
) strict;
CREATE TABLE file_type (
    [id] integer primary key,
    [name] text not null unique collate nocase
) strict;
CREATE TABLE asset_type (
    [id] integer primary key,
    [name] text not null unique collate nocase
) strict;
CREATE TABLE asset_group (
    [id] integer primary key,
    [name] text not null unique collate nocase
) strict;
CREATE TABLE asset (
    [id] integer primary key,
    [cdnid] text not null unique collate nocase,
    [gsfoid] integer not null unique,
    [file_type_id] integer not null references file_type(id) on delete restrict,
    [asset_type_id] integer references asset_type(id) on delete restrict,
    [asset_group_id] integer references asset_group(id) on delete restrict,
    [res_name] text collate nocase,
    [hash] text not null,
    [size] integer not null,
    [bundle_version] text
) strict;
CREATE TABLE avatar_slot (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [slot] text not null unique collate nocase,
    [animation] text
) strict;
CREATE TABLE asset_container (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [name] text not null unique collate nocase,
    [ptag] text collate nocase,
    [created_at] integer not null default (unixepoch())
) strict;
CREATE TABLE asset_container_assetmap (
    [id] integer primary key not null,
    [container_id] integer not null references asset_container(id) on delete cascade,
    [win_asset_id] integer not null references asset(id) on delete cascade,
    [osx_asset_id] integer references asset(id) on delete set null,
    [position] integer not null default 1,
    unique([container_id], [position]),
    unique([container_id], [win_asset_id])
) strict;
CREATE TABLE asset_container_package (
    [id] integer primary key not null,
    [container_id] integer not null references asset_container(id) on delete cascade,
    [pkg_container_id] integer not null references asset_container(id) on delete cascade,
    [position] integer not null default 1,
    unique([container_id], [position]),
    unique([container_id], [pkg_container_id])
) strict;
CREATE TABLE site_frame (
    [id] integer primary key not null,
    [type_value] integer not null unique,
    [container_id] integer not null references asset_container(id) on delete restrict
) strict;
CREATE TABLE avatar (
    [id] integer primary key,
    [container_id] integer not null unique references asset_container(id) on delete restrict,
    [name] text not null unique collate nocase
) strict;
CREATE TABLE player (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [username] text not null unique collate nocase,
    [password] text not null,
    [is_chat_allowed] integer default 1 check ([is_chat_allowed] in (0, 1)),
    [is_tutorial_completed] integer not null default 0 check ([is_tutorial_completed] in (0, 1)),
    [is_qa] integer not null default 0 check ([is_qa] in (0, 1)),
    [max_outfits] integer not null default 0,
    [created_at] integer not null default (unixepoch())
) strict;
CREATE TABLE player_avatar (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [player_id] integer not null references player(id) on delete cascade,
    [avatar_id] integer not null references avatar(id) on delete cascade,
    [name] text not null unique collate nocase,
    [outfit_no] integer not null default 1,
    [is_active] integer not null default 0 check ([is_active] in (0, 1)),
    unique([player_id], [avatar_id])
) strict;
CREATE TABLE player_avatar_outfit (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [player_avatar_id] integer not null references player_avatar(id) on delete cascade,
    [outfit_no] integer not null default 1,
    unique([player_avatar_id], [outfit_no])
) strict;
CREATE TABLE item_category (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [name] text not null unique collate nocase,
    [parent_id] integer references item_category(id) on delete restrict,
    [is_public] integer not null default 0 check ([is_public] in (0, 1)),
    [is_outdoor] integer not null default 0 check ([is_outdoor] in (0, 1)),
    [is_walkover] integer not null default 0 check ([is_walkover] in (0, 1)),
    [show_in_dock] integer not null default 0 check ([show_in_dock] in (0, 1))
) strict;
CREATE TABLE item (
    [id] integer primary key,
    [container_id] integer not null unique references asset_container(id) on delete restrict,
    [name] text not null unique collate nocase
) strict;
CREATE TABLE item_category_map (
    [id] integer primary key,
    [item_id] integer not null references item(id) on delete cascade,
    [category_id] integer not null references item_category(id) on delete restrict,
    unique([item_id], [category_id])
) strict;
CREATE TABLE item_acceptable_slot (
    [id] integer primary key,
    [item_id] integer not null references item(id) on delete cascade,
    [avatar_slot_id] integer not null references avatar_slot(id) on delete restrict,
    unique([item_id], [avatar_slot_id])
) strict;
CREATE TABLE player_item (
    [id] integer primary key,
    [gsfoid] integer not null unique,
    [player_id] integer not null references player(id) on delete cascade,
    [item_id] integer not null references item(id) on delete cascade,
    [player_avatar_id] integer references player_avatar(id) on delete set null,
    [player_avatar_outfit_id] integer references player_avatar_outfit(id) on delete set null,
    [avatar_slot_id] integer references avatar_slot(id) on delete set null,
    [quantity] integer not null default 1
) strict;
CREATE TABLE zone (
    [id] integer primary key,
    [container_id] integer not null unique references asset_container(id) on delete restrict
) strict;
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE INDEX random_name_part_type_ix on random_name([part_type]);
PRAGMA writable_schema=OFF;
COMMIT;
